  // references so removeEventListener tears down the exact functions.
  function onDocClick(): void {
    closeMenu();
  }
  function onDocKey(event: KeyboardEvent): void {
    if (event.key === 'Escape') {
      closeMenu();
    }
  }
  // The menu is position:fixed at viewport coords, so it detaches from its
  // owning row on scroll/resize. Dismiss it instead of leaving it stranded
  // over (potentially) the wrong row. Capturing on 'scroll' so it also fires
